const b = ($input.first().json.body) || {};
let ts = b.timestamp;
if (ts == null || ts === '') ts = Math.floor(Date.now()/1000);
else { ts = Number(ts); if (ts > 1e12) ts = Math.floor(ts/1000); }
const phone = b.phone ? String(b.phone).replace(/[^\d]/g,'') : null;
const ch = ['whatsapp','instagram','facebook'].includes(String(b.channel||'').toLowerCase()) ? String(b.channel).toLowerCase() : 'whatsapp';
const mediaUrl = b.mediaUrl || b.media_url || null;
const mediaMime = b.mediaMime || b.mimeType || b.mime || null;
const mediaName = b.filename || b.mediaFilename || b.fileName || null;
let mediaB64 = b.mediaBase64 || b.mediaData || b.media_base64 || null;
if (mediaB64) mediaB64 = String(mediaB64).replace(/^data:[^;]+;base64,/, '').replace(/\s/g, '');
const hasMedia = !!(mediaUrl || mediaB64);
const VALID = ['text','image','audio','video','document','sticker'];
let type = String(b.type||'').toLowerCase();
if (!VALID.includes(type)) type = hasMedia ? 'document' : 'text';
const text = b.text || '';
const LBL = { image:'\uD83D\uDCF7 Imagen', audio:'\uD83C\uDFB5 Audio', video:'\uD83C\uDFAC Video', sticker:'\uD83C\uDFAF Sticker', document:('\uD83D\uDCC4 '+(mediaName||'Documento')) };
const preview = text || LBL[type] || (hasMedia ? '\uD83D\uDCCE Adjunto' : '');
return [{ json: { contactId: b.contactId!=null ? String(b.contactId) : null, name: b.name||null, phone, text, wamid: b.wamid||null, ts, type, direction: 'out', status: b.status||'sent', channel: ch, mediaUrl, mediaMime, mediaName, mediaB64, preview } }];
